import * as React from "react"

import { Badge, StatGroup } from "@gunjo/ui"

import { BusDispatchConsole } from "./BusDispatchConsole"
import { DEPOT } from "./data"

export const metadata = {
  title: `配車・乗務員管理 ｜ ${DEPOT.company} ${DEPOT.name}`,
  description: "営業所の当日配車・乗務員（仕業/交番・点呼・拘束時間・資格）管理コンソール",
}

export default function BusDispatchPage() {
  return (
    <main className="mx-auto w-full max-w-[1480px] px-4 py-6 sm:px-6 lg:px-8">
      {/* ── ヘッダ ─────────────────────────────────────────────────────── */}
      <header className="mb-6 flex flex-wrap items-end justify-between gap-3 border-b border-border pb-4">
        <div>
          <div className="mb-1 flex items-center gap-2">
            <h1 className="text-xl font-bold tracking-tight">配車・乗務員管理</h1>
            <Badge variant="info">当日ダイヤ</Badge>
          </div>
          <p className="text-sm text-muted-foreground">
            {DEPOT.company}　{DEPOT.name}　/　{DEPOT.dateLabel}　/　{DEPOT.manager}
          </p>
        </div>
        <p className="text-xs text-muted-foreground" suppressHydrationWarning>
          最終更新 07:05　始発 05:12 ／ 終発 23:55
        </p>
      </header>

      {/* ── KPI ストリップ（RSC-safe・関数 props なし） ──────────────────── */}
      <div className="mb-6">
        <StatGroup
          cols={{ base: 2, md: 4 }}
          items={[
            { label: "出勤予定", value: "7名", hint: "公休1・年休1" },
            {
              label: "点呼合格",
              value: "2 / 5",
              change: "未了2・不合格1",
              trend: "down",
              tone: "negative",
            },
            {
              label: "要員過不足",
              value: "−2名",
              change: "代務手配中",
              trend: "down",
              tone: "negative",
              hint: "予備2名で充当検討",
            },
            {
              label: "要対応",
              value: "6件",
              change: "重大2",
              trend: "up",
              tone: "negative",
            },
          ]}
        />
      </div>

      {/* ── コンソール本体（クライアント境界） ───────────────────────────── */}
      <BusDispatchConsole />
    </main>
  )
}

"use client"

import * as React from "react"
import {
  IconAlertTriangle,
  IconBus,
  IconClipboardCheck,
  IconUserPlus,
} from "@tabler/icons-react"

import {
  ActionQueue,
  type ActionItem,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CoSign,
  type CoSignValue,
  flagValue,
  MetadataList,
  Meter,
  PersonCell,
  ReferenceValue,
  ScheduleGrid,
  type ScheduleCell,
  Separator,
  SignedRecord,
  type SignedRecordValue,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@gunjo/ui"

import {
  DRIVERS,
  type Driver,
  driverById,
  dutyById,
  fmtMin,
  LEGALITY,
  QUALIFICATIONS,
  ROLLCALLS,
  type RollCall,
  VEHICLES,
  type Currency,
} from "./data"

// ── 当日ダイヤの時間帯（交番の列） ─────────────────────────────────────────
const PERIODS = [
  { id: "p-early", label: "早朝", sublabel: "05–08" },
  { id: "p-am", label: "午前", sublabel: "08–11" },
  { id: "p-mid", label: "日中", sublabel: "11–14" },
  { id: "p-pm", label: "午後", sublabel: "14–17" },
  { id: "p-eve", label: "夜間", sublabel: "17–24" },
]

// 仕業を時間帯にざっくり割り付ける（早朝〜入庫の帯）。
const DUTY_SPAN: Record<string, { from: number; to: number; mid?: number }> = {
  "d-101": { from: 0, to: 2, mid: 1 }, // 05:12→14:30
  "d-205": { from: 0, to: 3, mid: 1 },
  "d-312": { from: 0, to: 3, mid: 2 },
  "d-418": { from: 2, to: 4, mid: 3 }, // 12:40→23:10
  "d-520": { from: 3, to: 4, mid: 4 }, // 16:30→翌01:05
}

const STATE_BADGE: Record<
  Driver["state"],
  { label: string; variant: React.ComponentProps<typeof Badge>["variant"] }
> = {
  assigned: { label: "乗務", variant: "info" },
  spare: { label: "予備", variant: "warning" },
  off: { label: "公休", variant: "outline" },
  leave: { label: "年休", variant: "outline" },
}

// 資格期限のステータス表示（有効/期限間近/失効）
const CURRENCY: Record<
  Currency,
  { label: string; variant: React.ComponentProps<typeof Badge>["variant"] }
> = {
  valid: { label: "有効", variant: "success" },
  expiring: { label: "期限間近", variant: "warning" },
  expired: { label: "失効", variant: "destructive" },
}

function rollById(id: string): RollCall | undefined {
  return ROLLCALLS.find((r) => r.driverId === id)
}

export function BusDispatchConsole() {
  const [selectedDriver, setSelectedDriver] = React.useState<string | null>("u-04")

  // ── 仕業・交番の割当グリッド（運転士 × 時間帯） ──────────────────────────
  // ScheduleGrid: rows = 運転士, columns = 時間帯, cells = 担当仕業の帯。
  const rosterRows = DRIVERS.map((d) => ({
    id: d.id,
    label: <span className="text-sm font-semibold">{d.name}</span>,
    sublabel: `#${d.empNo}`,
    ariaLabel: d.name,
  }))

  const rosterCells: ScheduleCell[] = React.useMemo(() => {
    const cells: ScheduleCell[] = []
    for (const d of DRIVERS) {
      if (d.state === "assigned" && d.dutyId) {
        const duty = dutyById(d.dutyId)
        const span = DUTY_SPAN[d.dutyId]
        if (!duty || !span) continue
        const roll = rollById(d.id)
        const rollFailed = roll?.stage === "failed"
        const rollPending = roll?.stage === "pending"
        for (let ci = span.from; ci <= span.to; ci++) {
          const isMid = ci === span.mid
          cells.push({
            rowId: d.id,
            colId: PERIODS[ci].id,
            tone: rollFailed
              ? "destructive"
              : ci === span.from
                ? "primary"
                : isMid
                  ? "muted"
                  : "info",
            content: (
              <div className="flex min-w-0 flex-col gap-0.5">
                {ci === span.from ? (
                  <>
                    <span className="text-xs font-semibold">{duty.code}</span>
                    <span className="truncate text-[11px] text-muted-foreground">
                      {duty.route}
                    </span>
                  </>
                ) : isMid ? (
                  <span className="text-[11px] text-muted-foreground">休憩</span>
                ) : ci === span.to ? (
                  <span className="text-[11px] text-muted-foreground">
                    {d.bus && d.bus !== "—" ? d.bus : "入庫"}
                  </span>
                ) : (
                  <span className="text-[11px] text-muted-foreground">運行</span>
                )}
              </div>
            ),
            description: `${duty.code} ${duty.route} ${
              rollFailed ? "点呼不合格" : rollPending ? "点呼未了" : ""
            }`,
            onSelect: () => setSelectedDriver(d.id),
          })
        }
      } else {
        // 公休 / 年休 / 予備 は全帯にステータスを表示
        const st = STATE_BADGE[d.state]
        cells.push({
          rowId: d.id,
          colId: PERIODS[0].id,
          tone: d.state === "spare" ? "warning" : "muted",
          content: <span className="text-xs font-medium">{st.label}</span>,
          description: st.label,
          onSelect: () => setSelectedDriver(d.id),
        })
        for (let ci = 1; ci < PERIODS.length; ci++) {
          cells.push({
            rowId: d.id,
            colId: PERIODS[ci].id,
            unavailable: d.state !== "spare",
            content:
              d.state === "spare" ? (
                <span className="text-[11px] text-muted-foreground">待機</span>
              ) : undefined,
            tone: "muted",
          })
        }
      }
    }
    return cells
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  // ── 要対応キュー ─────────────────────────────────────────────────────────
  const actionItems: ActionItem[] = [
    {
      id: "a-rc-03",
      severity: "critical",
      kind: "点呼不合格",
      title: "高橋 隆：アルコール検知 0.15 mg/L",
      detail: "出庫不可。代務手配と再点呼（30分後）を指示。3仕業 早81 の差替え要。",
      meta: "06:58",
      actions: (
        <Button size="xs" variant="destructive" onClick={() => setSelectedDriver("u-03")}>
          対応
        </Button>
      ),
    },
    {
      id: "a-lic-04",
      severity: "critical",
      kind: "資格失効",
      title: "田中 誠：大型二種免許 失効（2026-06-20）",
      detail: "乗務不可。4仕業 渋66 を予備運転士へ振替。免許更新の確認を要す。",
      meta: "本日",
      actions: (
        <Button size="xs" variant="outline" onClick={() => setSelectedDriver("u-04")}>
          確認
        </Button>
      ),
    },
    {
      id: "a-bind-04",
      severity: "warning",
      kind: "拘束時間",
      title: "田中 誠：拘束時間 12:42 / 13:00（上限接近）",
      detail: "残 18分。連続運転も 4:06 で超過。終発前の交替を検討。",
      meta: "98%",
    },
    {
      id: "a-rc-pending",
      severity: "warning",
      kind: "点呼未了",
      title: "未了 2名（田中・渡辺）",
      detail: "5仕業 出庫まで点呼・アルコールチェック未実施。",
      meta: "2件",
    },
    {
      id: "a-veh",
      severity: "warning",
      kind: "車両不足",
      title: "渋08号車 整備中 — 予備車なし",
      detail: "代務発生時に充当できる空き車両がありません。",
      meta: "1台",
    },
    {
      id: "a-apt-01",
      severity: "info",
      kind: "適性診断",
      title: "佐藤 健一：適性診断 受診期限 7/10",
      detail: "今週中に受診予約。期限超過で乗務制限。",
      meta: "残12日",
    },
  ]

  // ── 点呼記録の署名（SignedRecord） + 2人点呼（CoSign） ────────────────────
  const [record, setRecord] = React.useState<SignedRecordValue>({
    status: "draft",
    addenda: [],
  })
  const [coSign, setCoSign] = React.useState<CoSignValue | undefined>(undefined)

  // 全乗務員の点呼が pending を残していない（failed は addendum 対象）かどうか。
  const allRollResolved = ROLLCALLS.every((r) => r.stage !== "pending")

  const selected = selectedDriver ? driverById(selectedDriver) : undefined

  return (
    <TooltipProvider>
      <div className="flex w-full flex-col gap-6">
        {/* ── 中央：仕業・交番の割当 ─────────────────────────────────────── */}
        <Card>
          <CardHeader className="flex-row items-center justify-between gap-4 p-4">
            <div className="flex items-center gap-2">
              <IconBus className="size-5 text-muted-foreground" aria-hidden />
              <CardTitle as="h2" className="text-base">
                仕業・交番の割当（当日ダイヤ）
              </CardTitle>
            </div>
            <div className="flex items-center gap-2">
              <Badge variant="info">乗務 5</Badge>
              <Badge variant="warning">予備 2</Badge>
              <Badge variant="outline">公休 1</Badge>
              <Badge variant="outline">年休 1</Badge>
            </div>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <ScheduleGrid
              label="運転士別 仕業割当グリッド"
              cornerLabel="運転士＼帯"
              rowHeaderWidth={120}
              minColumnWidth={104}
              rows={rosterRows}
              columns={PERIODS}
              cells={rosterCells}
            />
            <p className="mt-3 text-xs text-muted-foreground">
              セルを選択すると右の詳細（点呼・拘束時間・資格）が切り替わります。赤いセル＝点呼不合格で出庫不可。
            </p>
          </CardContent>
        </Card>

        {/* ── 2カラム：点呼/拘束/資格 と 要対応/署名 ──────────────────────── */}
        <div className="grid gap-6 lg:grid-cols-[minmax(0,1.55fr)_minmax(0,1fr)]">
          {/* 左：点呼・拘束・資格のタブ */}
          <Card>
            <CardContent className="p-4">
              <Tabs defaultValue="rollcall" className="border-0">
                <TabsList className="mb-4">
                  <TabsTrigger value="rollcall">点呼</TabsTrigger>
                  <TabsTrigger value="legality">拘束時間</TabsTrigger>
                  <TabsTrigger value="qual">資格・期限</TabsTrigger>
                </TabsList>

                {/* 点呼（アルコールチェック＝基準値0.00 の閾値判定） */}
                <TabsContent value="rollcall" className="m-0">
                  <RollCallPanel />
                </TabsContent>

                {/* 拘束時間（消費 vs 上限の Meter） */}
                <TabsContent value="legality" className="m-0">
                  <LegalityPanel />
                </TabsContent>

                {/* 資格・期限（有効/期限間近/失効） */}
                <TabsContent value="qual" className="m-0">
                  <QualificationPanel />
                </TabsContent>
              </Tabs>
            </CardContent>
          </Card>

          {/* 右：要対応キュー＋配車＋詳細 */}
          <div className="flex flex-col gap-6">
            <Card>
              <CardHeader className="flex-row items-center gap-2 p-4 pb-2">
                <IconAlertTriangle className="size-5 text-warning" aria-hidden />
                <CardTitle as="h2" className="text-base">
                  要対応
                </CardTitle>
              </CardHeader>
              <CardContent className="p-4 pt-2">
                <ActionQueue items={actionItems} />
              </CardContent>
            </Card>

            {/* 選択中の運転士の詳細 */}
            {selected ? <DriverDetail driver={selected} /> : null}
          </div>
        </div>

        {/* ── 配車（号車 ↔ 仕業） ─────────────────────────────────────────── */}
        <Card>
          <CardHeader className="flex-row items-center gap-2 p-4 pb-2">
            <IconBus className="size-5 text-muted-foreground" aria-hidden />
            <CardTitle as="h2" className="text-base">
              配車（号車 ↔ 仕業）
            </CardTitle>
          </CardHeader>
          <CardContent className="grid gap-3 p-4 pt-2 sm:grid-cols-2 xl:grid-cols-3">
            {VEHICLES.map((v) => {
              const duty = v.dutyId ? dutyById(v.dutyId) : undefined
              const tone =
                v.state === "整備"
                  ? "destructive"
                  : v.state === "出庫"
                    ? "success"
                    : "outline"
              return (
                <div
                  key={v.id}
                  className="flex items-center justify-between gap-3 rounded-lg border border-border bg-card p-3"
                >
                  <div className="min-w-0">
                    <p className="text-sm font-semibold">{v.no}</p>
                    <p className="truncate text-xs text-muted-foreground">{v.model}</p>
                    <p className="mt-0.5 text-xs text-muted-foreground">
                      {duty ? `${duty.code}・${duty.route}` : "割当なし"}
                    </p>
                  </div>
                  <Badge variant={tone}>{v.state}</Badge>
                </div>
              )
            })}
          </CardContent>
        </Card>

        {/* ── 点呼記録・引継ぎの署名（lock-after-confirm） ──────────────────── */}
        <Card>
          <CardHeader className="flex-row items-center gap-2 p-4 pb-2">
            <IconClipboardCheck className="size-5 text-muted-foreground" aria-hidden />
            <CardTitle as="h2" className="text-base">
              当務点呼記録簿・引継ぎ（確定後ロック）
            </CardTitle>
          </CardHeader>
          <CardContent className="grid gap-6 p-4 pt-2 lg:grid-cols-2">
            <SignedRecord
              value={record}
              onChange={setRecord}
              signerId="橋本 学（運行管理者）"
              canSign={allRollResolved && coSign !== undefined}
              labels={{
                draft: "下書き（点呼確認中）",
                signed: "確定・署名済",
                sign: "点呼記録を確定する",
                locked: "確定済みの点呼記録は変更できません。修正・追補は追記で行います。",
                addendaTitle: "追記（運行中の変更・代務発生）",
                addendum: "追記する",
              }}
            >
              {({ readOnly }) => (
                <div className="flex flex-col gap-2 text-sm">
                  <MetadataList
                    layout="horizontal"
                    items={[
                      { label: "営業所", value: "渋谷営業所" },
                      { label: "対象ダイヤ", value: "2026-06-28(日)" },
                      { label: "出勤予定", value: "7名" },
                      { label: "点呼合格", value: "2名 / 未了2・不合格1" },
                      { label: "出庫済", value: "渋12・渋27号車" },
                      { label: "代務手配", value: "4仕業・3仕業（手配中）" },
                    ]}
                  />
                  {!readOnly ? (
                    <p className="text-xs text-muted-foreground">
                      未了の点呼が残っているか、2人点呼が未完了の間は確定できません。
                    </p>
                  ) : null}
                </div>
              )}
            </SignedRecord>

            <div className="flex flex-col gap-3">
              <p className="text-sm font-medium">2人点呼（補助者による確認）</p>
              <CoSign
                primaryId="橋本 学（運行管理者）"
                value={coSign}
                onSign={setCoSign}
                requireReason={false}
                signerLabel="補助点呼者ID（2人目）"
                attestations={[
                  { id: "att-alc", label: "全員のアルコールチェック値を確認した（0.00 mg/L）" },
                  { id: "att-health", label: "健康状態・睡眠・疲労を確認した" },
                  { id: "att-lic", label: "免許・適性診断の有効性を確認した" },
                ]}
                labels={{ sign: "2人点呼を完了する", signed: "2人点呼 完了" }}
              />
            </div>
          </CardContent>
        </Card>
      </div>
    </TooltipProvider>
  )
}

// ──────────────────────────────────────────────────────────────────────────
// 点呼パネル：アルコールチェックは ReferenceValue で 0.00 閾値判定
// ──────────────────────────────────────────────────────────────────────────
function RollCallPanel() {
  // 酒気帯び基準：検出（>0.00）で要対応。0.15 は明確に失格。
  const ALC_RANGE = { high: 0.0, criticalHigh: 0.15 } as const

  return (
    <div className="flex flex-col gap-2">
      <div className="grid grid-cols-[1.5fr_auto_auto_auto_auto] items-center gap-x-3 border-b border-border px-1 pb-1.5 text-xs font-medium text-muted-foreground">
        <span>運転士 / 仕業</span>
        <span className="text-right">アルコール</span>
        <span className="text-center">健康/疲労</span>
        <span className="text-center">点呼方法</span>
        <span className="text-right">状態</span>
      </div>
      {ROLLCALLS.map((r) => {
        const d = driverById(r.driverId)!
        const duty = d.dutyId ? dutyById(d.dutyId) : undefined
        const flag = flagValue(r.alcohol, ALC_RANGE)
        const stageBadge =
          r.stage === "passed" ? (
            <Badge variant="success">合格</Badge>
          ) : r.stage === "failed" ? (
            <Badge variant="destructive">不合格</Badge>
          ) : (
            <Badge variant="warning">未了</Badge>
          )
        return (
          <div
            key={r.driverId}
            className="grid grid-cols-[1.5fr_auto_auto_auto_auto] items-center gap-x-3 rounded-md px-1 py-2 text-sm odd:bg-muted/30"
          >
            <PersonCell
              name={d.name}
              secondary={duty ? `${duty.code}・${duty.route}` : d.rank}
              size="sm"
            />
            <span className="text-right">
              <ReferenceValue
                value={r.alcohol}
                range={ALC_RANGE}
                unit="mg/L"
                size="inline"
                format={(v) => v.toFixed(2)}
                labels={{
                  normal: "正常(0.00)",
                  high: "検出",
                  "critical-high": "酒気帯び",
                }}
                showLabel
              />
            </span>
            <span className="text-center text-xs text-muted-foreground">
              {r.health}/{r.fatigue}
            </span>
            <span className="text-center">
              <Badge variant={r.method === "対面" ? "info" : "outline"}>{r.method}</Badge>
            </span>
            <span className="flex items-center justify-end gap-2">
              {flag !== "normal" && r.stage !== "failed" ? (
                <Tooltip>
                  <TooltipTrigger asChild>
                    <span tabIndex={0} aria-label="アルコール検出: 要再点呼">
                      <IconAlertTriangle className="size-4 text-destructive" aria-hidden />
                    </span>
                  </TooltipTrigger>
                  <TooltipContent>アルコール検出。再点呼が必要です。</TooltipContent>
                </Tooltip>
              ) : null}
              {stageBadge}
            </span>
          </div>
        )
      })}
      <p className="mt-1 text-xs text-muted-foreground">
        アルコール基準：0.00 mg/L。検出（H）で再点呼、0.15 以上（HH）で出庫不可。
      </p>
    </div>
  )
}

// ──────────────────────────────────────────────────────────────────────────
// 拘束時間パネル：消費 vs 上限を Meter（改善基準告示）
// ──────────────────────────────────────────────────────────────────────────
function LegalityPanel() {
  return (
    <div className="flex flex-col gap-4">
      {LEGALITY.map((l) => {
        const d = driverById(l.driverId)!
        const duty = d.dutyId ? dutyById(d.dutyId) : undefined
        return (
          <div key={l.driverId} className="flex flex-col gap-2 rounded-lg border border-border p-3">
            <div className="flex items-center justify-between gap-2">
              <PersonCell
                name={d.name}
                secondary={duty ? `${duty.code}・${duty.route}` : d.rank}
                size="sm"
              />
              <span className="text-xs text-muted-foreground">改善基準告示</span>
            </div>
            <div className="grid gap-3 sm:grid-cols-3">
              <Meter
                label="拘束時間"
                value={l.bindingMin}
                max={l.bindingLimit}
                size="sm"
                formatValue={(v) => fmtMin(Math.round(v))}
                thresholds={{ warning: 0.9, over: 1 }}
              />
              <Meter
                label="運転時間"
                value={l.drivingMin}
                max={l.drivingLimit}
                size="sm"
                formatValue={(v) => fmtMin(Math.round(v))}
                thresholds={{ warning: 0.9, over: 1 }}
              />
              <Meter
                label="連続運転"
                value={l.continuousMin}
                max={l.continuousLimit}
                size="sm"
                formatValue={(v) => fmtMin(Math.round(v))}
                thresholds={{ warning: 0.9, over: 1 }}
              />
            </div>
          </div>
        )
      })}
      <p className="text-xs text-muted-foreground">
        拘束13時間/日（最大16）、運転時間2日平均9時間、連続運転4時間。90%超で警告、超過で要交替。
      </p>
    </div>
  )
}

