// ──────────────────────────────────────────────────────────────────────────
// 選択中運転士の詳細パネル
// ──────────────────────────────────────────────────────────────────────────
function DriverDetail({ driver }: { driver: Driver }) {
  const duty = driver.dutyId ? dutyById(driver.dutyId) : undefined
  const roll = rollById(driver.id)
  const leg = LEGALITY.find((l) => l.driverId === driver.id)
  const qual = QUALIFICATIONS.find((q) => q.driverId === driver.id)
  const stBadge = STATE_BADGE[driver.state]

  return (
    <Card>
      <CardHeader className="p-4 pb-2">
        <PersonCell
          name={driver.name}
          secondary={driver.rank}
          tertiary={`社員番号 #${driver.empNo}`}
          trailing={<Badge variant={stBadge.variant}>{stBadge.label}</Badge>}
        />
      </CardHeader>
      <CardContent className="flex flex-col gap-3 p-4 pt-2">
        <Separator />
        <MetadataList
          items={[
            { label: "担当仕業", value: duty ? `${duty.code}・${duty.route}` : "—" },
            { label: "配車", value: driver.bus && driver.bus !== "—" ? driver.bus : "未配車" },
            { label: "出退勤", value: duty ? duty.span : "—" },
            {
              label: "点呼",
              value: roll
                ? roll.stage === "passed"
                  ? `合格（${roll.method}・${roll.officer}）`
                  : roll.stage === "failed"
                    ? "不合格"
                    : "未了"
                : "対象外",
            },
            {
              label: "アルコール",
              value: roll ? `${roll.alcohol.toFixed(2)} mg/L` : "—",
            },
            {
              label: "拘束時間",
              value: leg ? `${fmtMin(leg.bindingMin)} / ${fmtMin(leg.bindingLimit)}` : "—",
            },
            {
              label: "免許",
              value: qual ? `${CURRENCY[qual.license.status].label}（${qual.license.date}）` : "—",
            },
          ]}
        />
        {(roll?.stage === "failed" || qual?.license.status === "expired") && (
          <div className="flex flex-wrap gap-2">
            <Button size="sm" variant="warning">
              <IconUserPlus className="size-4" aria-hidden />
              代務を手配
            </Button>
            <Button size="sm" variant="outline">
              予備運転士から充当
            </Button>
          </div>
        )}
      </CardContent>
    </Card>
  )
}

